import Spacings from '@dynatrace/strato-design-tokens/spacings';
import { formatDate } from '@dynatrace-sdk/units';

import { TooltipItem } from '../../../section-components/TooltipItem/TooltipItem.js';
import { TextHeader } from '../TextHeader.js';

/** @internal */
export interface TimestampHeaderProps {
  date: Date;
}

/** @internal */
export const TimestampHeader = ({ date }: TimestampHeaderProps) => {
  const formattedDate = formatDate(date, {
    day: '2-digit',
    month: 'short',
    year:
      date.getFullYear() === new Date().getFullYear() ? undefined : 'numeric',
    hour: '2-digit',
    minute: '2-digit',
    second: date.getSeconds() === 0 ? undefined : 'numeric',
  });

  return (
    <TooltipItem style={{ padding: `0 ${Spacings.Size2}` }}>
      <TextHeader text={formattedDate} />
    </TooltipItem>
  );
};

TimestampHeader['displayName'] = 'ChartTooltip.TimestampHeader';
